function def(e,t){const n=[...new Set([...t.matchAll(/{{([^\s{}]+)}}/g)].map(e=>e[1]))];customElements.define(e,class extends HTMLElement{static get observedAttributes(){return n}constructor(){super(),this.attachShadow({mode:"open"})}connectedCallback(){this.render()}attributeChangedCallback(e,t,n){t!==n&&this.render()}render(){let e=t;for(const t of n)e=e.replaceAll(`{{${t}}}`,this.getAttribute(t)??"");this.shadowRoot.innerHTML=e}})}